UPDATE PROJECT
SET progress = (
    SELECT NVL(ROUND(
        AVG(
            ROUND(
                (SELECT COUNT(*) 
                 FROM TASKDAILYLOG dl
                 JOIN EMPTASK et ON dl.empTaskId = et.empTaskId
                 WHERE et.taskId = t.taskId 
                 AND dl.logStatus = 'F') * 100.0
                / NULLIF(t.taskEndDate - t.taskStartDate + 1, 0)
            )
        )
    ), 0)
    FROM task t
    JOIN stage s ON t.stageId = s.stageId
    WHERE s.projectId = #{projectId}
)
WHERE projectId = #{projectId}

UPDATE PROJECT
SET status = '4'
WHERE projectId = #{projectId}
AND (
    SELECT COUNT(*)
    FROM task t
    JOIN stage s ON t.stageId = s.stageId
    WHERE s.projectId = #{projectId}
    AND t.taskStatus != '4'
) = 0
AND (
    SELECT COUNT(*)
    FROM task t
    JOIN stage s ON t.stageId = s.stageId
    WHERE s.projectId = #{projectId}
) > 0
